mapper.select:
/* 사용자 목록 조회 */
select * from (
	select 
		@rownum := @rownum + 1 as rnum,
		page_tb.*
	from (
			select 
				user_idx, user_id, user_pw, user_type, main_user_idx, main_user_yn, auth_type, lang_type, 
				co_name, co_tel, co_email, psn_name, psn_dept, psn_tel, psn_mobile, psn_email, note, 
				del_yn, reg_uid, reg_date, mod_uid, mod_date 
			from tb_user
			where del_yn = 'N'
			order by reg_date
	) page_tb
	,  ( select @rownum := 0 ) r
) f_tb
limit #{startNum }, #{pageRowCnt }
